1	const KNOWN_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
2	
3	function validateItemTypes(items: any[]): void {
4	  for (const item of items) {
5	    if (!KNOWN_TYPES.includes(item.type)) {
6	      throw new Error(`Unknown item type: ${item.type}`);
7	    }
8	  }
9	}
10	
11	const PROCESSING_FEE = 5;
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	function basePremium(item: any): number {
23	  return BASE_PREMIUMS[item.type] ?? 0;
24	}
25	
26	const COMPONENT_TYPES = ["rune", "moonstone"];
27	const BLOCK_SIZE = 3;
28	const BLOCK_PREMIUM = 60;
29	
30	function isComponent(item: any): boolean {
31	  return COMPONENT_TYPES.includes(item.type);
32	}
33	
34	function groupByType(items: any[]): Record<string, any[]> {
35	  const result: Record<string, any[]> = {};
36	  for (const item of items) {
37	    if (!result[item.type]) result[item.type] = [];
38	    result[item.type].push(item);
39	  }
40	  return result;
41	}
42	
43	function componentGroupPremium(group: any[]): number {
44	  if (group.length === BLOCK_SIZE) return BLOCK_PREMIUM;
45	  return group.reduce((sum: number, item: any) => sum + basePremium(item), 0);
46	}
47	
48	export function claimOffice(input: any): unknown {
49	  const results = [];
50	  let quoteCount = 0;
51	  for (const step of input.steps) {
52	    validateItemTypes(step.items);
53	
54	    const components = step.items.filter(isComponent);
55	    const nonComponents = step.items.filter((i: any) => !isComponent(i));
56	
57	    let rawPolicyBase = 0;
58	    let itemSpecificSurcharges = 0;
59	
60	    for (const item of nonComponents) {
61	      const base = basePremium(item);
62	      rawPolicyBase += base;
63	      if (item.cursed) {
64	        itemSpecificSurcharges += base * 0.5;
65	      }
66	      if (item.enchantment >= 5) {
67	        itemSpecificSurcharges += base * 0.3;
68	      }
69	    }
70	
71	    for (const group of Object.values(groupByType(components))) {
72	      rawPolicyBase += componentGroupPremium(group);
73	    }
74	
75	    let policyWideModifier = 0;
76	
77	    // First insurance surcharge: 10% of policy base premium (always applies)
78	    policyWideModifier += rawPolicyBase * 0.1;
79	
80	    if (input.customer.yearsWithMHPCO >= 2) {
81	      policyWideModifier -= rawPolicyBase * 0.2;
82	    }
83	
84	    quoteCount++;
85	    if (quoteCount > 1) {
86	      policyWideModifier -= rawPolicyBase * 0.15;
87	    }
88	
89	    const premium = Math.ceil(rawPolicyBase + itemSpecificSurcharges + policyWideModifier + PROCESSING_FEE);
90	
91	    results.push({ premium });
92	  }
93	  return { results };
94	}
